{"path":"music.py","content":""""Simple melody using the built-in winsound module (Windows only).
No external dependencies required.
"""
import sys

# winsound is only available on Windows. Fallback to a simple print if unavailable.
try:
    import winsound
except ImportError:
    winsound = None

# Define notes (frequency in Hz) and durations (ms)
MELODY = [
    (440, 500),  # A4
    (494, 500),  # B4
    (523, 500),  # C5
    (587, 500),  # D5
    (659, 500),  # E5
    (698, 500),  # F5
    (784, 500),  # G5
    (880, 500),  # A5
]

def play_melody():
    if winsound:
        for freq, dur in MELODY:
            winsound.Beep(freq, dur)
    else:
        # Simple fallback: print notes
        for freq, dur in MELODY:
            print(f"Beep: {freq}Hz for {dur}ms")

if __name__ == "__main__":
    play_melody()
"}
